import{_ as a,o as r,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"24. Weekend Work","description":"","frontmatter":{"title":"24. Weekend Work","eba":"Health Allied & Managers Admin 2021-2025","topics":["wages"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/hours-of-work/24-weekend-work.md","filePath":"ebas/has-managers-admin/health-allied-services/hours-of-work/24-weekend-work.md"}'),o={name:"ebas/has-managers-admin/health-allied-services/hours-of-work/24-weekend-work.md"};function n(d,e,l,i,h,k){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_24-weekend-work" tabindex="-1">24. Weekend Work <a class="header-anchor" href="#_24-weekend-work" aria-label="Permalink to &quot;24. Weekend Work&quot;">​</a></h1><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>24.1</strong> All rostered time of ordinary duty performed between midnight on Friday and Midnight on Sunday will be paid for at the rate of 150% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>).</p><p><strong>24.2</strong> Where the Saturday or Sunday work involves work in excess of the prescribed rostered hours, such work will be paid for at the rate of 200% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>).</p><p>Plain language terms: weekend penalty, weekend loading, Saturday rate, Sunday rate.</p>',5)])])}const p=a(o,[["render",n]]);export{m as __pageData,p as default};
